example.code:
uses(RefreshDatabase::class);

beforeEach(function () {
    $this->organization = Organization::factory()->create();
    $this->admin = User::factory()->for($this->organization)->create(['role' => 'admin']);
});

it('can create a user', function () {
    $response = $this->actingAs($this->admin)->postJson('/api/v1/users', [
        'name' => 'Jane Doe', 'email' => 'jane@example.com', 'password' => 'SecurePass123!',
    ]);
    $response->assertCreated()->assertJsonPath('data.email', 'jane@example.com');
    $this->assertDatabaseHas('users', ['email' => 'jane@example.com']);
});

it('validates unique email within organization', function () {
    User::factory()->for($this->organization)->create(['email' => 'taken@example.com']);
    $this->actingAs($this->admin)->postJson('/api/v1/users', [
        'name' => 'Test', 'email' => 'taken@example.com', 'password' => 'SecurePass123!',
    ])->assertUnprocessable()->assertJsonValidationErrors(['email']);
});
